// GenerateToken creates a signed JWT token for a user. This is provided for
// demonstration/testing purposes. In production, token issuance would typically
// be handled by a dedicated auth service.
func GenerateToken(config *JWTConfig, userID, username, email string, roles []string, duration time.Duration) (string, error) {
	// Enforce a maximum token lifetime to prevent long-lived tokens.
	maxDuration := 24 * time.Hour
	if duration > maxDuration {
		return "", fmt.Errorf("token duration exceeds maximum allowed (%v)", maxDuration)
	}

	if duration <= 0 {
		return "", fmt.Errorf("token duration must be positive")
	}

	now := time.Now()
	claims := &UserClaims{
		UserID:   userID,
		Username: username,
		Email:    email,
		Roles:    roles,
		RegisteredClaims: jwt.RegisteredClaims{
			Issuer:    config.ExpectedIssuer,
			Audience:  jwt.ClaimStrings{config.ExpectedAudience},
			Subject:   userID,
			ExpiresAt: jwt.NewNumericDate(now.Add(duration)),
			IssuedAt:  jwt.NewNumericDate(now),
			NotBefore: jwt.NewNumericDate(now),
			ID:        fmt.Sprintf("%d", now.UnixNano()),
		},
	}

	// Use only the explicitly allowed algorithm (HS256).
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString(config.SecretKey)
}

